#!/usr/bin/env node

/**
 * Bundle script: Combines the modular src/ structure back into a single App.jsx
 * for uploading to Canvas or any environment that needs a single-file React component.
 *
 * Usage:
 *   node scripts/bundle.js              # writes to dist/App.jsx
 *   node scripts/bundle.js --stdout     # prints to stdout
 */

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");
const SRC = path.join(ROOT, "src");

function read(relPath) {
  return fs.readFileSync(path.join(SRC, relPath), "utf-8");
}

// ─── Parse source files ────────────────────────────────────────────────────

// 1. Collect all unique lucide-react imports across all files
const lucideImports = new Set();
const lucidePattern = /import\s*\{([^}]+)\}\s*from\s*["']lucide-react["'];?/g;
const allFiles = [
  "constants/brand.js",
  "components/TypewriterHeading.jsx",
  "components/CanvasWave.jsx",
  "components/DownloadButton.jsx",
  "components/Navbar.jsx",
  "components/Footer.jsx",
  "components/views/ConceptView.jsx",
  "components/views/LogoView.jsx",
  "components/views/TypographyView.jsx",
  "components/views/ColorSystemView.jsx",
  "components/PrintLayout.jsx",
];

for (const f of allFiles) {
  const content = read(f);
  let match;
  while ((match = lucidePattern.exec(content)) !== null) {
    match[1].split(",").forEach((s) => {
      const trimmed = s.trim();
      if (trimmed) lucideImports.add(trimmed);
    });
  }
}

// 2. Extract module bodies (strip imports/exports, get the meat)
function extractBody(content) {
  return content
    .replace(/^import\s+.*$/gm, "")
    .replace(/^export\s+default\s+/gm, "const __default__ = ")
    .replace(/^export\s+(const|function|class)\s+/gm, "$1 ")
    .replace(/^export\s+\{[^}]*\};?\s*$/gm, "")
    .trim();
}

// ─── Read all modules ──────────────────────────────────────────────────────

const brandConstants = extractBody(read("constants/brand.js"));
const svgTemplates = extractBody(read("constants/svgTemplates.js"));
const imageUtils = extractBody(read("lib/imageUtils.js"));
const downloadFile = extractBody(read("lib/downloadFile.js"));
const exportAppJsx = extractBody(read("constants/exportAppJsx.js"));

const typewriterHeading = extractBody(read("components/TypewriterHeading.jsx"));
const canvasWave = extractBody(read("components/CanvasWave.jsx"));
const downloadButton = extractBody(read("components/DownloadButton.jsx"));
const navbar = extractBody(read("components/Navbar.jsx"));
const footer = extractBody(read("components/Footer.jsx"));
const printLayout = extractBody(read("components/PrintLayout.jsx"));

const conceptView = extractBody(read("components/views/ConceptView.jsx"));
const logoView = extractBody(read("components/views/LogoView.jsx"));
const typographyView = extractBody(read("components/views/TypographyView.jsx"));
const colorSystemView = extractBody(read("components/views/ColorSystemView.jsx"));

const useDownloads = extractBody(read("hooks/useDownloads.js"));
const appComponent = extractBody(read("App.jsx"));

// ─── Assemble ──────────────────────────────────────────────────────────────

const lucideImportLine = `import {\n  ${[...lucideImports].sort().join(",\n  ")},\n} from "lucide-react";`;

const bundled = `// ============================================================================
// Kinetic Forms Brandbook — Single-file bundle
// Generated by: node scripts/bundle.js
// Date: ${new Date().toISOString().split("T")[0]}
//
// This file is auto-generated from the modular src/ structure.
// Edit the individual source files, then re-run the bundle script.
// ============================================================================

import React, { useState, useEffect, useRef } from "react";
${lucideImportLine}

// --- Constants: Brand ---
${brandConstants}

// --- Constants: SVG Templates ---
${svgTemplates}

// --- Constants: Export App JSX ---
${exportAppJsx}

// --- Lib: Image Utils ---
${imageUtils}

// --- Lib: Download File ---
${downloadFile}

// --- Hook: useDownloads ---
${useDownloads}

// --- Component: TypewriterHeading ---
${typewriterHeading.replace("const __default__ = ", "const TypewriterHeading = ")}

// --- Component: CanvasWave ---
${canvasWave.replace("const __default__ = ", "const CanvasWave = ")}

// --- Component: DownloadButton ---
${downloadButton.replace("const __default__ = ", "const DownloadButton = ")}

// --- Component: Navbar ---
${navbar.replace("const __default__ = ", "const Navbar = ")}

// --- Component: Footer ---
${footer.replace("const __default__ = ", "const Footer = ")}

// --- Component: PrintLayout ---
${printLayout.replace("const __default__ = ", "const PrintLayout = ")}

// --- View: ConceptView ---
${conceptView.replace("const __default__ = ", "const ConceptView = ")}

// --- View: LogoView ---
${logoView.replace("const __default__ = ", "const LogoView = ")}

// --- View: TypographyView ---
${typographyView.replace("const __default__ = ", "const TypographyView = ")}

// --- View: ColorSystemView ---
${colorSystemView.replace("const __default__ = ", "const ColorSystemView = ")}

// --- App ---
${appComponent.replace("const __default__ = ", "const App = ")}

export default App;
`;

// ─── Output ────────────────────────────────────────────────────────────────

if (process.argv.includes("--stdout")) {
  process.stdout.write(bundled);
} else {
  const outDir = path.join(ROOT, "dist");
  if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true });
  const outPath = path.join(outDir, "App.jsx");
  fs.writeFileSync(outPath, bundled);
  console.log(`Bundled App.jsx written to ${outPath}`);
  console.log(`  Lines: ${bundled.split("\n").length}`);
}
